def _validate_user(username: str, password: str) -> bool:
    # Replace with real authentication.
    # For internal use: allow either a shared password or empty password if explicitly enabled.
    shared_password = _get_env("SHARED_PASSWORD", None)
    allow_empty = _get_env("ALLOW_EMPTY_PASSWORD", "false").lower() in ("1", "true", "yes")
    if shared_password is not None:
        return password == shared_password and bool(username)
    if allow_empty:
        return bool(username)
    return False


def _user_attributes(username: str) -> dict:
    # Replace with real directory lookup.
    return {
        "email": username,
        "uid": username.split("@")[0] if "@" in username else username,
        "displayName": username,
        "groups": ["internal"],
    }


@app.post("/login")
def login():
    saml_request_b64 = request.form.get("SAMLRequest")
    relay_state = request.form.get("RelayState", "")
    username = (request.form.get("username") or "").strip()
    password = request.form.get("password") or ""

    if not saml_request_b64:
        abort(400, "Missing SAMLRequest")

    if not _validate_user(username, password):
        return Response("Invalid credentials", status=401)

    # Parse AuthnRequest to get ACS URL and SP Issuer
    # To construct settings we need sp_entity_id and acs_url.
    # Prefer values from request; optionally use configured defaults.
    dummy_settings = _make_settings(sp_entity_id=_get_env("SP_ENTITY_ID", "urn:example:sp"), acs_url=_get_env("SP_ACS_URL", "https://sp.example.com/acs"), sp_x509cert=None)
    parsed = _parse_authn_request(dummy_settings, saml_request_b64)

    sp_entity_id = parsed.get("issuer") or _get_env("SP_ENTITY_ID", "urn:example:sp")
    acs_url = parsed.get("acs_url") or _get_env("SP_ACS_URL", "https://sp.example.com/acs")

    # Optional: load SP x509cert from env (only needed if you intend to verify signed AuthnRequests)
    sp_x509cert = _get_env("SP_X509CERT", "")

    settings = _make_settings(sp_entity_id=sp_entity_id, acs_url=acs_url, sp_x509cert=sp_x509cert if sp_x509cert else None)

    in_response_to = parsed.get("id")
    session_index = "_" + uuid.uuid4().hex
    attrs = _user_attributes(username)

    saml_response_xml = _build_signed_saml_response_xml(
        settings=settings,
        request_id=in_response_to or "_" + uuid.uuid4().hex,
        acs_url=acs_url,
        in_response_to=in_response_to,
        nameid=username,
        attributes=attrs,
        session_index=session_index,
    )

    saml_response_b64 = _base64_encode(saml_response_xml)

    html = _render_auto_post_form(acs_url=acs_url, saml_response_b64=saml_response_b64, relay_state=relay_state if relay_state != "" else None)
    resp = make_response(html)
    resp.headers["Content-Type"] = "text/html"
    return resp


def _ssl_context():
    cert = _get_env("TLS_CERT", "./tls.crt")
    key = _get_env("TLS_KEY", "./tls.key")
    if not (os.path.exists(cert) and os.path.exists(key)):
        return None
    return (cert, key)


